// T211 RecurringBillingEngine — status before lock
async runBillingCycle(subscriptionId: string): Promise<DataProcessResult<void>> {
  // ORDER 1: Status check — MUST precede lock
  const status = await this.db.getDocument('xiigen-subscriptions', subscriptionId);
  if (!status.isSuccess) return DataProcessResult.failure('NOT_FOUND', 'Subscription not found');

  const subStatus = status.data?.['status'] as string;
  if (subStatus === 'CANCELLED' || subStatus === 'PAUSED') {
    // Early return — no lock acquired for ineligible subscriptions
    await this.queue.enqueue('InvoiceVoided', { subscriptionId, reason: subStatus });
    return DataProcessResult.success(undefined);
  }

  // ORDER 2: Lock acquisition (only for ACTIVE subscriptions)
  const lockKey = hash(tenantId + subscriptionId + billingPeriod);
  const locked = await this.setnx(lockKey);
  if (!locked) return DataProcessResult.failure('ALREADY_BILLED', 'Billing cycle already in progress');

  // ... process invoice, run dunning from FREEDOM config ...

// ❌ WRONG: lock at ORDER 1, status at ORDER 2 — consumes lock slot for CANCELLED subscription
